// MARK: - Rate Limiter

final class RateLimiter {
    private var attempts: [(date: Date, identifier: String)] = []
    private let maxAttempts: Int
    private let windowSeconds: TimeInterval
    private let queue = DispatchQueue(label: "com.myapp.ratelimiter", attributes: .concurrent)
    
    init(maxAttempts: Int = 5, windowSeconds: TimeInterval = 300) {
        self.maxAttempts = maxAttempts
        self.windowSeconds = windowSeconds
    }
    
    func shouldAllow(identifier: String) -> Bool {
        var result = false
        queue.sync(flags: .barrier) {
            let now = Date()
            // Prune old entries
            attempts.removeAll { now.timeIntervalSince($0.date) > windowSeconds }
            
            let recentCount = attempts.filter { $0.identifier == identifier }.count
            if recentCount < maxAttempts {
                attempts.append((date: now, identifier: identifier))
                result = true
            } else {
                result = false
            }
        }
        return result
    }
}

