// MARK: - Universal Link Validator & Parser

final class UniversalLinkHandler {
    
    private let rateLimiter = RateLimiter(maxAttempts: 5, windowSeconds: 300)
    
    /// Validates and parses a universal link URL for password reset.
    /// Returns a strongly-typed PasswordResetDeepLink on success.
    func parsePasswordResetLink(from url: URL) -> Result<PasswordResetDeepLink, UniversalLinkError> {
        
        // 1. Parse URL components safely
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return .failure(.invalidURL)
        }
        
        // 2. Validate scheme (HTTPS only)
        guard let scheme = components.scheme?.lowercased(),
              UniversalLinkConfig.allowedSchemes.contains(scheme) else {
            return .failure(.disallowedScheme(components.scheme))
        }
        
        // 3. Validate host against strict allowlist
        guard let host = components.host?.lowercased(),
              UniversalLinkConfig.allowedHosts.contains(host) else {
            return .failure(.disallowedHost(components.host))
        }
        
        // 4. Normalize and validate path against allowlist
        let normalizedPath = normalizePath(components.path)
        guard UniversalLinkConfig.allowedPaths.contains(normalizedPath) else {
            return .failure(.disallowedPath(normalizedPath))
        }
        
        // 5. Extract and validate token parameter
        guard let queryItems = components.queryItems,
              let tokenItem = queryItems.first(where: { $0.name == "token" }),
              let token = tokenItem.value,
              !token.isEmpty else {
            return .failure(.missingToken)
        }
        
        // 6. Validate token format with strict regex
        guard isValidTokenFormat(token) else {
            return .failure(.invalidTokenFormat)
        }
        
        // 7. Rate limit by token to prevent brute-force
        let rateLimitIdentifier = tokenFingerprint(token)
        guard rateLimiter.shouldAllow(identifier: rateLimitIdentifier) else {
            return .failure(.rateLimitExceeded)
        }
        
        // 8. Ensure no unexpected query parameters (defense in depth)
        let allowedParams: Set<String> = ["token"]
        let providedParams = Set(queryItems.map { $0.name })
        guard providedParams.isSubset(of: allowedParams) else {
            return .failure(.invalidURL)
        }
        
        let deepLink = PasswordResetDeepLink(token: token, host: host, path: normalizedPath)
        return .success(deepLink)
    }
    
    // MARK: - Private Helpers
    
    /// Normalizes a URL path: lowercases, removes trailing slashes, collapses double slashes.
    private func normalizePath(_ path: String) -> String {
        var normalized = path.lowercased()
        // Remove any double slashes
        while normalized.contains("//") {
            normalized = normalized.replacingOccurrences(of: "//", with: "/")
        }
        // Remove trailing slash unless it's the root
        if normalized.count > 1 && normalized.hasSuffix("/") {
            normalized = String(normalized.dropLast())
        }
        // Resolve any path traversal attempts
        let resolvedComponents = normalized.split(separator: "/").reduce(into: [Substring]()) { result, component in
            if component == ".." {
                result.removeLast()
            } else if component != "." {
                result.append(component)
            }
        }
        normalized = "/" + resolvedComponents.joined(separator: "/")
        return normalized
    }
    
    /// Validates token format using a strict regex pattern.
    private func isValidTokenFormat(_ token: String) -> Bool {
        guard let regex = try? NSRegularExpression(pattern: UniversalLinkConfig.tokenPattern) else {
            return false
        }
        let range = NSRange(token.startIndex..., in: token)
        return regex.firstMatch(in: token, options: [], range: range) != nil
    }
    
    /// Creates a fingerprint of the token for rate limiting without storing the raw token.
    private func tokenFingerprint(_ token: String) -> String {
        let data = Data(token.utf8)
        let hash = SHA256.hash(data: data)
        return hash.prefix(8).map { String(format: "%02x", $0) }.joined()
    }
}

