// MARK: - Password Reset Service (Backend Communication)

final class PasswordResetService {
    static let shared = PasswordResetService()
    
    private let baseURL = "https://api.myapp.com"
    private let session: URLSession
    
    private init() {
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        session = URLSession(configuration: config)
    }
    
    func validateToken(_ token: String, completion: @escaping (Result<Void, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/api/v1/password-reset/validate") else {
            completion(.failure(NSError(domain: "PasswordReset", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid API URL"])))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.timeoutInterval = 15
        
        let body: [String: String] = ["token": token]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(NSError(domain: "PasswordReset", code: -2, userInfo: [NSLocalizedDescriptionKey: "Invalid response"])))
                return
            }
            
            switch httpResponse.statusCode {
            case 200:
                completion(.success(()))
            case 401, 403:
                completion(.failure(NSError(domain: "PasswordReset", code: 401, userInfo: [NSLocalizedDescriptionKey: "This reset link is invalid or has expired."])))
            case 429:
                completion(.failure(NSError(domain: "PasswordReset", code: 429, userInfo: [NSLocalizedDescriptionKey: "Too many attempts. Please try again later."])))
            default:
                completion(.failure(NSError(domain: "PasswordReset", code: httpResponse.statusCode, userInfo: [NSLocalizedDescriptionKey: "An unexpected error occurred."])))
            }
        }.resume()
    }
    
    func resetPassword(token: String, newPassword: String, completion: @escaping (Result<Void, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/api/v1/password-reset/confirm") else {
            completion(.failure(NSError(domain: "PasswordReset", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid API URL"])))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.timeoutInterval = 15
        
        let body: [String: String] = [
            "token": token,
            "new_password": newPassword
        ]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(NSError(domain: "PasswordReset", code: -2, userInfo: [NSLocalizedDescriptionKey: "Invalid response"])))
                return
            }
            
            switch httpResponse.statusCode {
            case 200:
                completion(.success(()))
            case 401, 403:
                completion(.failure(NSError(domain: "PasswordReset", code: 401, userInfo: [NSLocalizedDescriptionKey: "This reset link is invalid or has expired."])))
            case 422:
                completion(.failure(NSError(domain: "PasswordReset", code: 422, userInfo: [NSLocalizedDescriptionKey: "Password does not meet requirements."])))
            default:
                completion(.failure(NSError(domain: "PasswordReset", code: httpResponse.statusCode, userInfo: [NSLocalizedDescriptionKey: "An unexpected error occurred."])))
            }
        }.resume()
    }
}

// MARK: - App Delegate Integration

class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    private let linkHandler = UniversalLinkHandler()
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        window = UIWindow(frame: UIScreen.main.bounds)
        let rootVC = UINavigationController(rootViewController: HomeViewController())
        window?.rootViewController = rootVC
        window?.makeKeyAndVisible()
        return true
    }
    
    // MARK: - Universal Link Handling
    
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        
        return handleUniversalLink(url)
    }
    
    private func handleUniversalLink(_ url: URL) -> Bool {
        let result = linkHandler.parsePasswordResetLink(from: url)
        
        switch result {
        case .success(let deepLink):
            navigateToPasswordReset(token: deepLink.token)
            return true
            
        case .failure(let error):
            // Log the error securely (no token values in logs)
            print("[UniversalLink] Rejected link: \(error.description)")
            showErrorAlert(for: error)
            return false
        }
    }
    
    private func navigateToPasswordReset(token: String) {
        guard let navigationController = window?.rootViewController as? UINavigationController else {
            return
        }
        
        // Dismiss any presented view controllers first
        navigationController.dismiss(animated: false)
        
        // Pop to root to ensure clean navigation state
        navigationController.popToRootViewController(animated: false)
        
        let resetVC = PasswordResetViewController(token: token)
        navigationController.pushViewController(resetVC, animated: true)
    }
    
    private func showErrorAlert(for error: UniversalLinkError) {
        guard let rootVC = window?.rootViewController else { return }
        
        // Use a generic message for security - don't reveal specifics about why validation failed
        let userMessage: String
        switch error {
        case .rateLimitExceeded:
            userMessage = "Too many attempts. Please try again later."
        default:
            userMessage = "This password reset link is invalid or has expired. Please request a new one."
        }
        
        let alert = UIAlertController(
            title: "Invalid Link",
            message: userMessage,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        DispatchQueue.main.async {
            rootVC.present(alert, animated: true)
        }
    }
}

